customCSS:
@media only screen and (min-width: 1200px) {
	.cHeaderTop {
		background-image: url('/sfsites/c/resource/UCP_Community_Assets/CommunityAssets/bg-header10.png');
        background-repeat: no-repeat;
		padding-top: 0 !important;
        height: 130px;
		width:100%;
	}

	.cHeaderTopInternalWrapper {
		display: block;
		height: inherit;
		padding: 0 !important;
	}



	.cLogo {
		display: none;
	}



	.cptNavBar {
		/*background: #1B347E;*/
		bottom: 0;
		position: absolute;
		width: 100%;
	}



	.siteforceCptBody .comm-navigation {
		max-width: 100% !important;
	}



	.forceCommunityGlobalNavigation>* {
		margin: 0 !important;
	}

	.comm-navigation__item > button, .comm-navigation__item > a {
		text-transform: uppercase !important;
	}


	.comm-navigation__item ul li.slds-list__item button {
		color: #1B347E !important;
	}


	.cSearchContainer {
		position: absolute;
		right: 3%;
		top: 50px;
        width:20% !important;
        min-width:20% !important;
	}



	.cNotifications {
		position: absolute;
		right: 0;
		top: 15px;
	}



	.cProfileMenu {
		position: absolute;
		right: 3%;
		top: 5px;
	}



	.selfServiceUserProfileMenu a.trigger-link {
		color: white !important;
	}



	.forceCommunityGlobalSearchInput .inputWrapper {
		background: white;
	}



	.forceSearchInputDesktop .contentWrapper {
		border-radius: 50px !important;
	}



	.slds-icon-utility-notification svg[data-key="notification"] {fill: white !important;}

	.siteforceContentArea {
		padding: 0 100px;
	}

	.siteforceContentArea.siteforceSldsOneColLayout, .siteforceContentArea.siteforceDynamicLayout {
		padding: 0 !important;
	}
}



@media only screen and (max-width: 30em) {
	#CustomerPortalTemplate {
	overflow-x: hidden !important;
	}

	.siteforceCptBody .cHeader .cAltToggleNav .slds-button__icon {
	color:white!important;
	}

	.siteforceCptBody .cHeader .cSearchInvokeMobile .slds-icon {
	fill:white!important;
	}

	.siteforceCptBody .cHeader .selfServiceProfileMenuTrigger .profileName{
	color:white!important;
	}

    .slds-global-actions__notifications{
        display:none !important;
    }
}



@media only screen and (min-width: 30em) and (max-width: 48em) {
	.cSearchContainer {
		position: absolute;
		right: 20%;
		top: 10px;
		width:21% !important;
        min-width:21% !important;
	}



	.cNotifications {
		position: absolute;
		right: 14%;
		top: 15px;
	}



	.cProfileMenu {
		position: absolute;
		right: 1%;
		top: 15px;
	}

	.siteforceContentArea {
		padding: 0 !important;
	}

	.siteforceCptBody .cHeader .cAltToggleNav .slds-button__icon {
		color:white;
	}

	.siteforceCptBody .cHeader .cSearchInvokeMobile .slds-icon {
		fill:white;
	}

	.siteforceCptBody .cHeader .selfServiceProfileMenuTrigger .profileName{
		color:white;
	}
}



@media screen and (min-width: 1024px) and (max-width: 1366px) {
	.siteforceContentArea {
		padding: 0 !important;
	}

}

/* Hide Edit Button on My Profile */
.forceCommunityUserProfileDetail .userDetailHeader{ 
        display:none !important;
    }

/* Hide Global Search */
.forceCommunityGlobalSearchInput{
    display:none !important;
}

/* Hide Bell Notification */
.unsNotificationsCounter .headerButtonBody{
    display:none !important;
}

/* Hide Notififcation Box */
.slds-global-actions__notifications{
    display:none !important;
}

div[data-target-selection-name*='.Follow'] {    display: none;}
li[data-target-selection-name*='.FeedItem.ContentNote'] {    display: none;}
li[data-target-selection-name="sfdc:StandardButton.AttachedContentDocument.AttachFileFromDevice"] { display:none;}
.forceContentRelatedListPreviewFileList .lightningInput .slds-file-selector__dropzone {display:none;}
.forceCommunityFileDetailPage .slds-size_1-of-3 {display:none;}
